MERGE INTO 
	TRAINING_BOOK_DETAIL
USING DUAL ON (
	HOMEPAGE_ID = #{homepage_id}
	AND GROUP_IDX = #{group_idx}
	AND CATEGORY_IDX = #{category_idx}
	AND TRAINING_IDX = #{training_idx}
	AND TRAINING_BOOK_TIME_IDX = #{training_book_time_idx} 
	AND STUDENT_IDX = #{student_idx}
)
WHEN MATCHED
THEN
	UPDATE SET
		PAY1 = #{pay1},
		PAY2 = #{pay2},
		PAY3 = #{pay3},
		STATUS = #{status},
		MOD_DATE = SYSDATE,
		MOD_ID = #{mod_id}
WHEN NOT MATCHED 
